```class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> result = new ArrayList<>();
        long sum = 0;
        for (long i = 2; i <= finalSum; i += 2) {
            if (sum + i > finalSum) break;
            sum += i;
            result.add(i);
        }
        if (sum < finalSum) return new ArrayList<>();
        return result;
    }
}```
